def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        base_multiplier = 1.0
        adj_factor = 1.0
        for j in range(1, 15):
            if j % 3 == 0 and j % 5 == 0:
                base_multiplier *= 1.1
                adj_factor *= 0.95
            elif j % 3 == 0:
                base_multiplier *= 0.98
            elif j % 5 == 0:
                base_multiplier *= 1.05
            weight = (np.sin(j) + np.cos(ratio * j)) * base_multiplier
            if ratio < 0.1 * j:
                score += (j ** 2) * np.exp(-ratio * j) * weight
            else:
                score += (np.log1p(j * ratio) + ratio ** 3) * weight / (j + 2)
            if cap % (j + 2) == 0:
                score *= 1.05
            elif (cap + j * 2) % 4 == 0:
                score *= 0.93
            else:
                score *= 1.0 + 0.01 * (-1) ** j
            if j % 7 == 0:
                for k in range(1, 7):
                    diff = cap - item * k
                    if diff == 0:
                        score += 10 / (k + 1)
                    elif diff > 0:
                        if diff % 3 == 0:
                            score += np.log1p(diff) / (k + 2)
                        else:
                            score -= np.sqrt(abs(diff)) / (k + 3)
                    else:
                        penalty = abs(diff) ** 1.3 / (k + 1)
                        if penalty > score * 0.5:
                            score -= penalty * 1.5
                        else:
                            score -= penalty
            if score < -1000 or score > 1000:
                score /= np.log1p(abs(score))
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap + item) * adj_factor
        else:
            if cap > item * 4:
                priorities[i] = -score / (np.sqrt(cap) + 1) * adj_factor
            else:
                priorities[i] = -score / (cap + 3) * adj_factor
        if ratio > 0.85:
            priorities[i] *= 1.3
        elif ratio < 0.05:
            priorities[i] *= 0.75
        elif 0.4 < ratio < 0.6:
            priorities[i] *= 0.9
        if i % 2 == 0:
            priorities[i] *= 1.05
        else:
            priorities[i] *= 0.95
    return priorities
